# ─── Notebook 3: EDA Multimodal ──────────────────────────────────

NOTEBOOKS["03_eda_multimodal.ipynb"] = {
 "nbformat": 4,
 "nbformat_minor": 5,
 "metadata": {"kernelspec": {"display_name": "Python 3", "language": "python", "name": "python3"},
               "language_info": {"name": "python", "version": "3.10.0"}},
 "cells": [
  {"cell_type":"markdown","metadata":{},"source":["# 📊 EDA – Multimodal Dataset (CIFAR-100 Superclasses + CLIP)\n\n**CO5085 – Assignment 1**\n\nMục đích: Khám phá tập dữ liệu đa phương thức dùng CIFAR-100 superclasses làm proxy với text prompts tự động."],"id":"mm_e01"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["import sys\nsys.path.append('../src')\nimport numpy as np\nimport matplotlib.pyplot as plt\nimport seaborn as sns\nimport torch, clip\nfrom torchvision import datasets\nimport torchvision.transforms as T\nfrom collections import Counter\nimport os\nos.makedirs('../results', exist_ok=True)\n\nDEVICE = 'cuda' if torch.cuda.is_available() else 'cpu'\nprint(f'Libraries loaded ✅ | Device: {DEVICE}')"],"id":"mm_e02"},
  {"cell_type":"markdown","metadata":{},"source":["## 1. Dataset Overview"],"id":"mm_e03"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["# CIFAR-100 superclasses (20 groups used as multimodal class labels)\nSUPERCLASSES = [\n    'aquatic mammals', 'fish', 'flowers', 'food containers', 'fruit and vegetables',\n    'household electrical devices', 'household furniture', 'insects', 'large carnivores',\n    'large man-made outdoor things', 'large natural outdoor scenes', 'large omnivores and herbivores',\n    'medium-sized mammals', 'non-insect invertebrates', 'people', 'reptiles',\n    'small mammals', 'trees', 'vehicles 1', 'vehicles 2'\n]\n\ncoarse_labels = [\n    4, 1, 14, 8, 0, 6, 7, 7, 18, 3, 3, 14, 9, 18, 7, 11, 3, 9, 7, 11,\n    6, 11, 5, 10, 7, 6, 13, 15, 3, 15, 0, 11, 1, 10, 12, 14, 16, 9, 11, 5,\n    5, 19, 8, 8, 15, 13, 14, 17, 18, 10, 16, 4, 17, 4, 2, 0, 17, 4, 18, 17,\n    10, 3, 2, 12, 12, 16, 12, 1, 9, 19, 2, 10, 0, 1, 16, 12, 9, 13, 15, 13,\n    16, 19, 2, 4, 6, 19, 5, 5, 8, 19, 18, 1, 2, 15, 6, 0, 17, 8, 14, 13\n]\n\ntrain_ds = datasets.CIFAR100(root='../data/image', train=True, download=True,\n                              transform=T.ToTensor())\ntest_ds  = datasets.CIFAR100(root='../data/image', train=False, download=True,\n                              transform=T.ToTensor())\nprint(f'Train: {len(train_ds)} | Test: {len(test_ds)} | Superclasses: {len(SUPERCLASSES)}')"],"id":"mm_e04"},
  {"cell_type":"markdown","metadata":{},"source":["## 2. Superclass Distribution"],"id":"mm_e05"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["train_coarse = [coarse_labels[y] for _, y in train_ds]\ncounts = Counter(train_coarse)\n\nplt.figure(figsize=(14, 5))\nplt.bar([SUPERCLASSES[i] for i in sorted(counts)], [counts[i] for i in sorted(counts)], color='mediumpurple')\nplt.xticks(rotation=45, ha='right', fontsize=8)\nplt.title('CIFAR-100 Superclass Distribution (Train)')\nplt.ylabel('Count')\nplt.tight_layout()\nplt.savefig('../results/multimodal_superclass_dist.png', dpi=150)\nplt.show()\nprint(f'Samples per superclass – Min: {min(counts.values())} | Max: {max(counts.values())}')"],"id":"mm_e06"},
  {"cell_type":"markdown","metadata":{},"source":["## 3. Sample Image-Text Pairs"],"id":"mm_e07"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["fig, axes = plt.subplots(4, 5, figsize=(15, 12))\nshown = {}\nfor img_t, fine_label in train_ds:\n    sc = coarse_labels[fine_label]\n    if sc not in shown:\n        shown[sc] = (img_t, SUPERCLASSES[sc])\n    if len(shown) == 20:\n        break\n\nfor ax, (sc_idx, (img_t, prompt)) in zip(axes.flat, sorted(shown.items())):\n    ax.imshow(img_t.permute(1, 2, 0).clamp(0, 1))\n    ax.set_title(f'\\'a photo of a {prompt}\\'', fontsize=7, wrap=True)\n    ax.axis('off')\n\nplt.suptitle('Image–Text Pairs (one sample per superclass)', fontsize=13, fontweight='bold')\nplt.tight_layout()\nplt.savefig('../results/multimodal_image_text_pairs.png', dpi=150)\nplt.show()"],"id":"mm_e08"},
  {"cell_type":"markdown","metadata":{},"source":["## 4. Text Prompt Statistics (CLIP Tokenizer)"],"id":"mm_e09"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["# Load CLIP tokenizer (no model weights needed for this)\nmodel_clip, preprocess = clip.load('ViT-B/32', device='cpu')\n\nprompts = [f'a photo of a {sc}' for sc in SUPERCLASSES]\ntoken_lengths = [len(clip.tokenize(p)[0].nonzero()) for p in prompts]\n\nprint('Text prompt token lengths:')\nfor prompt, tlen in zip(prompts, token_lengths):\n    print(f'  [{tlen:2d} tokens] {prompt}')\nprint(f'\\nMean: {np.mean(token_lengths):.1f} | Max: {max(token_lengths)}')"],"id":"mm_e10"},
  {"cell_type":"markdown","metadata":{},"source":["## 5. CLIP Embedding Space Visualization (PCA)"],"id":"mm_e11"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["from sklearn.decomposition import PCA\n\n# Encode all 20 text prompts\nwith torch.no_grad():\n    tokens = clip.tokenize(prompts).to('cpu')\n    text_features = model_clip.encode_text(tokens).float().numpy()\n\npca = PCA(n_components=2)\ncoords = pca.fit_transform(text_features)\n\nplt.figure(figsize=(10, 7))\nfor i, (x, y) in enumerate(coords):\n    plt.scatter(x, y, s=80, color='coral')\n    plt.annotate(SUPERCLASSES[i], (x, y), fontsize=8, textcoords='offset points', xytext=(5, 3))\n\nplt.title('CLIP Text Embeddings – PCA (20 Superclass Prompts)')\nplt.xlabel('PC1')\nplt.ylabel('PC2')\nplt.tight_layout()\nplt.savefig('../results/multimodal_clip_text_pca.png', dpi=150)\nplt.show()\nprint(f'Explained variance: PC1={pca.explained_variance_ratio_[0]:.2%}, PC2={pca.explained_variance_ratio_[1]:.2%}')"],"id":"mm_e12"},
 ]
}

