NOTEBOOKS["05_text_rnn_transformer.ipynb"] = {
 "nbformat": 4,
 "nbformat_minor": 5,
 "metadata": {"kernelspec": {"display_name": "Python 3", "language": "python", "name": "python3"},
               "language_info": {"name": "python", "version": "3.10.0"}},
 "cells": [
  {"cell_type":"markdown","metadata":{},"source":["# 📝 Text Classification: RNN vs. Transformer\n\n**CO5085 – Assignment 1**\n\nSo sánh: **BiLSTM, GRU** vs. **DistilBERT, BERT-base**"],"id":"txt01"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["import sys\nsys.path.append('../src')\nimport torch, os\nos.makedirs('../results', exist_ok=True)\nDEVICE = 'cuda' if torch.cuda.is_available() else 'cpu'\nprint(f'Device: {DEVICE}')"],"id":"txt02"},
  {"cell_type":"markdown","metadata":{},"source":["## 1. Load Data (20 Newsgroups + DistilBERT Tokenizer)"],"id":"txt03"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["from datasets import get_20newsgroups_loaders\ntrain_loader, val_loader, test_loader, tokenizer, num_classes = get_20newsgroups_loaders(\n    tokenizer_name='distilbert-base-uncased', batch_size=32, max_length=256)\nprint(f'Classes: {num_classes} | Train batches: {len(train_loader)}')"],"id":"txt04"},
  {"cell_type":"markdown","metadata":{},"source":["## 2. Model 1: DistilBERT (Transformer)"],"id":"txt05"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["from models import get_distilbert\nfrom train import train\n\ndistilbert = get_distilbert(num_classes=num_classes)\nhistory_distilbert = train(distilbert, train_loader, val_loader,\n                           num_epochs=5, lr=2e-5, weight_decay=1e-2,\n                           device=DEVICE, save_path='../results/distilbert_best.pt',\n                           scheduler_type='cosine')"],"id":"txt06"},
  {"cell_type":"markdown","metadata":{},"source":["## 3. Model 2: BERT-base (Transformer)"],"id":"txt07"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["from models import get_bert\n\n# Use bert tokenizer for separate loader\nfrom datasets import get_20newsgroups_loaders\ntrain_bert, val_bert, test_bert, tok_bert, _ = get_20newsgroups_loaders(\n    tokenizer_name='bert-base-uncased', batch_size=16, max_length=256)\n\nbert_model = get_bert(num_classes=num_classes)\nhistory_bert = train(bert_model, train_bert, val_bert,\n                     num_epochs=5, lr=2e-5,\n                     device=DEVICE, save_path='../results/bert_best.pt')"],"id":"txt08"},
  {"cell_type":"markdown","metadata":{},"source":["## 4. BiLSTM (RNN)\n\n> **Note**: BiLSTM uses a simple vocabulary tokenizer instead of WordPiece."],"id":"txt09"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["# Build vocab from training data\nfrom sklearn.datasets import fetch_20newsgroups\nfrom sklearn.model_selection import train_test_split\nfrom torch.utils.data import DataLoader, TensorDataset\nimport torch\nimport numpy as np\n\nraw = fetch_20newsgroups(subset='train', remove=('headers','footers','quotes'))\nfrom collections import Counter\nwords = Counter(' '.join(raw.data).lower().split())\nvocab = {w: i+2 for i,(w,_) in enumerate(words.most_common(50000))}\nvocab['<pad>'] = 0\nvocab['<unk>'] = 1\nVOCAB_SIZE = len(vocab)\n\ndef tokenize_simple(texts, max_len=256):\n    result = []\n    for text in texts:\n        ids = [vocab.get(w, 1) for w in text.lower().split()[:max_len]]\n        ids = ids + [0] * (max_len - len(ids))\n        result.append(ids)\n    return torch.tensor(result, dtype=torch.long)\n\ntr_texts, val_texts, tr_labels, val_labels = train_test_split(\n    raw.data, raw.target, test_size=0.15, random_state=42)\n\ntr_X  = tokenize_simple(tr_texts)\nval_X = tokenize_simple(val_texts)\ntest_raw = fetch_20newsgroups(subset='test', remove=('headers','footers','quotes'))\ntest_X = tokenize_simple(test_raw.data)\n\ntrain_lstm = DataLoader(TensorDataset(tr_X, torch.tensor(tr_labels, dtype=torch.long)), batch_size=64, shuffle=True)\nval_lstm   = DataLoader(TensorDataset(val_X, torch.tensor(val_labels, dtype=torch.long)), batch_size=64)\ntest_lstm  = DataLoader(TensorDataset(test_X, torch.tensor(list(test_raw.target), dtype=torch.long)), batch_size=64)\n\nprint(f'Vocab size: {VOCAB_SIZE}')"],"id":"txt10"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["from models import BiLSTMClassifier\nfrom train import train\n\nbilstm = BiLSTMClassifier(vocab_size=VOCAB_SIZE, embed_dim=128, hidden_dim=256,\n                           num_layers=2, num_classes=20, dropout=0.4)\nhistory_bilstm = train(bilstm, train_lstm, val_lstm,\n                       num_epochs=15, lr=1e-3,\n                       device=DEVICE, save_path='../results/bilstm_best.pt')"],"id":"txt11"},
  {"cell_type":"markdown","metadata":{},"source":["## 5. Evaluation & Comparison"],"id":"txt12"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["from evaluate import compute_metrics, plot_training_curves, compare_models, get_predictions\n\nresults_text = {}\n\n# DistilBERT\npreds, labels, _ = get_predictions(distilbert, test_loader, DEVICE)\nresults_text['DistilBERT'] = compute_metrics(preds, labels, verbose=True)\nplot_training_curves(history_distilbert, 'DistilBERT', '../results/distilbert_curves.png')\n\n# BERT\npreds, labels, _ = get_predictions(bert_model, test_bert, DEVICE)\nresults_text['BERT-base'] = compute_metrics(preds, labels, verbose=True)\nplot_training_curves(history_bert, 'BERT-base', '../results/bert_curves.png')\n\n# BiLSTM (note: returns plain tensors, not dicts)\nimport torch, torch.nn as nn\nbilstm.eval()\nall_p, all_l = [], []\nwith torch.no_grad():\n    for xb, yb in test_lstm:\n        out = bilstm(xb.to(DEVICE))\n        all_p += out.argmax(-1).cpu().tolist()\n        all_l += yb.tolist()\nimport numpy as np\nresults_text['BiLSTM'] = compute_metrics(np.array(all_p), np.array(all_l), verbose=True)\n\ncompare_models(results_text, metric='accuracy', save_path='../results/text_comparison_acc.png')\ncompare_models(results_text, metric='f1_macro',  save_path='../results/text_comparison_f1.png')"],"id":"txt13"},
 ]
}

# ─── Notebook 6: Multimodal (CLIP) ───────────────────────────────

NOTEBOOKS["06_multimodal_zeroshot_fewshot.ipynb"] = {
 "nbformat": 4,
 "nbformat_minor": 5,
 "metadata": {"kernelspec": {"display_name": "Python 3", "language": "python", "name": "python3"},
               "language_info": {"name": "python", "version": "3.10.0"}},
 "cells": [
  {"cell_type":"markdown","metadata":{},"source":["# 🔀 Multimodal: Zero-shot vs. Few-shot (CLIP)\n\n**CO5085 – Assignment 1**\n\nDùng CLIP để so sánh zero-shot và few-shot classification trên tập đa phương thức (Flickr30k/COCO subset)."],"id":"mm01"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["import sys\nsys.path.append('../src')\nimport torch, clip, numpy as np\nimport matplotlib.pyplot as plt\nfrom PIL import Image\nfrom pathlib import Path\nimport os\nos.makedirs('../results', exist_ok=True)\n\nDEVICE = 'cuda' if torch.cuda.is_available() else 'cpu'\nmodel, preprocess = clip.load('ViT-B/32', device=DEVICE)\nprint(f'CLIP loaded on {DEVICE} ✅')"],"id":"mm02"},
  {"cell_type":"markdown","metadata":{},"source":["## 1. Dataset Preparation\n\nSử dụng CIFAR-100 super-classes (20 classes) làm **proxy multimodal dataset** với:\n- Ảnh từ CIFAR-100\n- Text prompt tự động: `'a photo of a {superclass}'`\n\n> Nếu có Flickr30k, thay bằng dataset đó."],"id":"mm03"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["from torchvision import datasets\nimport torchvision.transforms as T\n\n# CIFAR-100 superclasses (20 groups)\nSUPERCLASSES = [\n    'aquatic mammals', 'fish', 'flowers', 'food containers', 'fruit and vegetables',\n    'household electrical devices', 'household furniture', 'insects', 'large carnivores',\n    'large man-made outdoor things', 'large natural outdoor scenes', 'large omnivores and herbivores',\n    'medium-sized mammals', 'non-insect invertebrates', 'people', 'reptiles',\n    'small mammals', 'trees', 'vehicles 1', 'vehicles 2'\n]\n\n# CIFAR-100 maps each fine class to a superclass\ncoarse_labels = [\n    4, 1, 14, 8, 0, 6, 7, 7, 18, 3, 3, 14, 9, 18, 7, 11, 3, 9, 7, 11,\n    6, 11, 5, 10, 7, 6, 13, 15, 3, 15, 0, 11, 1, 10, 12, 14, 16, 9, 11, 5,\n    5, 19, 8, 8, 15, 13, 14, 17, 18, 10, 16, 4, 17, 4, 2, 0, 17, 4, 18, 17,\n    10, 3, 2, 12, 12, 16, 12, 1, 9, 19, 2, 10, 0, 1, 16, 12, 9, 13, 15, 13,\n    16, 19, 2, 4, 6, 19, 5, 5, 8, 19, 18, 1, 2, 15, 6, 0, 17, 8, 14, 13\n]\n\ntest_ds = datasets.CIFAR100(root='../data/image', train=False, download=True,\n                             transform=T.Compose([T.Resize(224), T.ToTensor()]))\ntest_images = [T.ToPILImage()(test_ds[i][0]) for i in range(500)]\ntest_labels = [coarse_labels[test_ds[i][1]] for i in range(500)]\nprint(f'Test samples: {len(test_images)} | Superclasses: {len(SUPERCLASSES)}')"],"id":"mm04"},
  {"cell_type":"markdown","metadata":{},"source":["## 2. Zero-shot Classification"],"id":"mm05"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["from models import CLIPZeroShotClassifier\n\nzero_clf = CLIPZeroShotClassifier(class_names=SUPERCLASSES, device=DEVICE)\nBATCH = 50\nall_preds = []\nfor i in range(0, len(test_images), BATCH):\n    batch_imgs = test_images[i:i+BATCH]\n    _, preds = zero_clf.predict(batch_imgs)\n    all_preds.extend(preds.tolist())\n\nfrom sklearn.metrics import accuracy_score, f1_score\nacc_zs = accuracy_score(test_labels, all_preds)\nf1_zs  = f1_score(test_labels, all_preds, average='macro', zero_division=0)\nprint(f'Zero-shot → Accuracy: {acc_zs:.4f} | F1-Macro: {f1_zs:.4f}')"],"id":"mm06"},
  {"cell_type":"markdown","metadata":{},"source":["## 3. Few-shot Classification (CLIP + Linear Probe)"],"id":"mm07"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["from models import CLIPFewShotClassifier\nimport torch.nn as nn\nfrom torch.optim import Adam\n\ndef run_few_shot(k_shots_per_class: int):\n    \"\"\"Train linear probe with k examples per class.\"\"\"\n    clf = CLIPFewShotClassifier(num_classes=len(SUPERCLASSES), device=DEVICE).to(DEVICE)\n\n    # Build few-shot training set\n    from collections import defaultdict\n    class_examples = defaultdict(list)\n    for idx in range(len(test_ds)):\n        img, fine_label = test_ds[idx]\n        coarse = coarse_labels[fine_label]\n        if len(class_examples[coarse]) < k_shots_per_class:\n            class_examples[coarse].append(T.ToPILImage()(img))\n    \n    # Extract CLIP features\n    support_imgs, support_labels = [], []\n    for c, imgs in class_examples.items():\n        support_imgs.extend(imgs)\n        support_labels.extend([c] * len(imgs))\n    \n    X_support = clf.encode_images(support_imgs)\n    y_support = torch.tensor(support_labels, dtype=torch.long).to(DEVICE)\n\n    # Train linear head\n    optimizer = Adam(clf.classifier.parameters(), lr=1e-2)\n    criterion = nn.CrossEntropyLoss()\n    for _ in range(200):\n        optimizer.zero_grad()\n        logits = clf.classifier(X_support)\n        loss = criterion(logits, y_support)\n        loss.backward()\n        optimizer.step()\n\n    # Evaluate\n    clf.eval()\n    test_feats = clf.encode_images(test_images)\n    with torch.no_grad():\n        logits = clf.classifier(test_feats)\n        preds = logits.argmax(-1).cpu().numpy()\n\n    acc = accuracy_score(test_labels, preds)\n    f1  = f1_score(test_labels, preds, average='macro', zero_division=0)\n    print(f'  {k_shots_per_class}-shot → Acc: {acc:.4f}, F1: {f1:.4f}')\n    return acc, f1\n\nresults_mm = {'Zero-shot': {'accuracy': acc_zs, 'f1_macro': f1_zs}}\nfor k in [1, 5, 10, 20]:\n    acc, f1 = run_few_shot(k)\n    results_mm[f'{k}-shot'] = {'accuracy': acc, 'f1_macro': f1}"],"id":"mm08"},
  {"cell_type":"markdown","metadata":{},"source":["## 4. Comparison Chart"],"id":"mm09"},
  {"cell_type":"code","execution_count":None,"metadata":{},"outputs":[],"source":["from evaluate import compare_models\ncompare_models(results_mm, metric='accuracy', save_path='../results/multimodal_comparison_acc.png')"],"id":"mm10"},
 ]
}

